const typeData = {"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicy":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicy","fields":[{"fieldName":"TypeMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.TypeMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"ObjectMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.ObjectMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"Spec","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicySpec","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Specification of the desired behavior of AdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["Specification of the desired behavior of AdminNetworkPolicy."]}]}},{"fieldName":"Status","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyStatus","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Status is the status to be reported by the implementation.\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Status is the status to be reported by the implementation."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":true,"isTopLevel":true,"docString":"+genclient\n+genclient:nonNamespaced\n+kubebuilder:object:root=true\n+kubebuilder:subresource:status\n+kubebuilder:resource:shortName=anp,scope=Cluster\n+kubebuilder:printcolumn:name=\"Priority\",type=string,JSONPath=\".spec.priority\"\n+kubebuilder:printcolumn:name=\"Age\",type=\"date\",JSONPath=\".metadata.creationTimestamp\"\n+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object\nAdminNetworkPolicy is  a cluster level resource that is part of the\nAdminNetworkPolicy API.","parsedDocString":{"elements":[{"type":"d","content":["+genclient"]},{"type":"d","content":["+genclient:nonNamespaced"]},{"type":"d","content":["+kubebuilder:object:root=true"]},{"type":"d","content":["+kubebuilder:subresource:status"]},{"type":"d","content":["+kubebuilder:resource:shortName=anp,scope=Cluster"]},{"type":"d","content":["+kubebuilder:printcolumn:name=\"Priority\",type=string,JSONPath=\".spec.priority\""]},{"type":"d","content":["+kubebuilder:printcolumn:name=\"Age\",type=\"date\",JSONPath=\".metadata.creationTimestamp\""]},{"type":"d","content":["+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object"]},{"type":"p","content":["AdminNetworkPolicy is  a cluster level resource that is part of the AdminNetworkPolicy API."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyEgressPeer":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyEgressPeer","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces defines a way to select all pods within a set of Namespaces.\nNote that host-networked pods are not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces defines a way to select all pods within a set of Namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr"],"docString":"Pods defines a way to select a set of pods in\na set of namespaces. Note that host-networked pods\nare not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods defines a way to select a set of pods in a set of namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Nodes","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Nodes defines a way to select a set of nodes in\nthe cluster (based on the node's labels). It selects\nthe nodeIPs as the peer type by matching on the IPs\npresent in the node.Status.Addresses field of the node.\nThis field follows standard label selector\nsemantics; if present but empty, it selects all Nodes.\n\n\u003cnetwork-policy-api:experimental\u003e\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Nodes defines a way to select a set of nodes in the cluster (based on the node's labels). It selects the nodeIPs as the peer type by matching on the IPs present in the node.Status.Addresses field of the node. This field follows standard label selector semantics; if present but empty, it selects all Nodes."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental\u003e"]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Networks","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.CIDR","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"Networks defines a way to select peers via CIDR blocks.\nThis is intended for representing entities that live outside the cluster,\nwhich can't be selected by pods, namespaces and nodes peers, but note\nthat cluster-internal traffic will be checked against the rule as\nwell. So if you Allow or Deny traffic to `\"0.0.0.0/0\"`, that will allow\nor deny all IPv4 pod-to-pod traffic as well. If you don't want that,\nadd a rule that Passes all pod traffic before the Networks rule.\n\nEach item in Networks should be provided in the CIDR format and should be\nIPv4 or IPv6, for example \"10.0.0.0/8\" or \"fd00::/8\".\n\nNetworks can have upto 25 CIDRs specified.\n\n+optional\n+listType=set\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Networks defines a way to select peers via CIDR blocks. This is intended for representing entities that live outside the cluster, which can't be selected by pods, namespaces and nodes peers, but note that cluster-internal traffic will be checked against the rule as well. So if you Allow or Deny traffic to `\"0.0.0.0/0\"`, that will allow or deny all IPv4 pod-to-pod traffic as well. If you don't want that, add a rule that Passes all pod traffic before the Networks rule."]},{"type":"p","content":["Each item in Networks should be provided in the CIDR format and should be IPv4 or IPv6, for example \"10.0.0.0/8\" or \"fd00::/8\"."]},{"type":"p","content":["Networks can have upto 25 CIDRs specified."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+listType=set"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}},{"fieldName":"DomainNames","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.DomainName","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"DomainNames provides a way to specify domain names as peers.\n\nDomainNames is only supported for ALLOW rules. In order to control\naccess, DomainNames Allow rules should be used with a lower priority\negress deny -- this allows the admin to maintain an explicit \"allowlist\"\nof reachable domains.\n\nDomainNames can have up to 25 domain names specified in one rule.\n\n\u003cnetwork-policy-api:experimental\u003e\n+optional\n+listType=set\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["DomainNames provides a way to specify domain names as peers."]},{"type":"p","content":["DomainNames is only supported for ALLOW rules. In order to control access, DomainNames Allow rules should be used with a lower priority egress deny -- this allows the admin to maintain an explicit \"allowlist\" of reachable domains."]},{"type":"p","content":["DomainNames can have up to 25 domain names specified in one rule."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental\u003e"]},{"type":"d","content":["+optional"]},{"type":"d","content":["+listType=set"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyEgressPeer defines a peer to allow traffic to.\n\nExactly one of the fields must be set for a given peer and this is enforced\nby the validation rules on the CRD. If an implementation sees no fields are\nset then it can infer that the deployed CRD is of an incompatible version\nwith an unknown field.  In that case it should fail closed.\n\nFor \"Allow\" rules, \"fail closed\" means: \"treat the rule as matching no\ntraffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule\nas a 'Deny all' rule\".\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyEgressPeer defines a peer to allow traffic to."]},{"type":"p","content":["Exactly one of the fields must be set for a given peer and this is enforced by the validation rules on the CRD. If an implementation sees no fields are set then it can infer that the deployed CRD is of an incompatible version with an unknown field.  In that case it should fail closed."]},{"type":"p","content":["For \"Allow\" rules, \"fail closed\" means: \"treat the rule as matching no traffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule as a 'Deny all' rule\"."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyEgressRule":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyEgressRule","fields":[{"fieldName":"Name","typeName":"string","package":"","typeDecorators":null,"docString":"Name is an identifier for this rule, that may be no more than 100 characters\nin length. This field should be used by the implementation to help\nimprove observability, readability and error-reporting for any applied\nAdminNetworkPolicies.\n\n+optional\n+kubebuilder:validation:MaxLength=100","parsedDocString":{"elements":[{"type":"p","content":["Name is an identifier for this rule, that may be no more than 100 characters in length. This field should be used by the implementation to help improve observability, readability and error-reporting for any applied AdminNetworkPolicies."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxLength=100"]}]}},{"fieldName":"Action","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyRuleAction","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Action specifies the effect this rule will have on matching traffic.\nCurrently the following actions are supported:\nAllow: allows the selected traffic (even if it would otherwise have been denied by NetworkPolicy)\nDeny: denies the selected traffic\nPass: instructs the selected traffic to skip any remaining ANP rules, and\nthen pass execution to any NetworkPolicies that select the pod.\nIf the pod is not selected by any NetworkPolicies then execution\nis passed to any BaselineAdminNetworkPolicies that select the pod.","parsedDocString":{"elements":[{"type":"p","content":["Action specifies the effect this rule will have on matching traffic. Currently the following actions are supported: Allow: allows the selected traffic (even if it would otherwise have been denied by NetworkPolicy) Deny: denies the selected traffic Pass: instructs the selected traffic to skip any remaining ANP rules, and then pass execution to any NetworkPolicies that select the pod. If the pod is not selected by any NetworkPolicies then execution is passed to any BaselineAdminNetworkPolicies that select the pod."]}]}},{"fieldName":"To","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyEgressPeer","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"To is the List of destinations whose traffic this rule applies to.\nIf any element matches the destination of outgoing\ntraffic then the specified action is applied.\nThis field must be defined and contain at least one item.\n\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["To is the List of destinations whose traffic this rule applies to. If any element matches the destination of outgoing traffic then the specified action is applied. This field must be defined and contain at least one item."]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}},{"fieldName":"Ports","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyPort","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr","List"],"docString":"Ports allows for matching traffic based on port and protocols.\nThis field is a list of destination ports for the outgoing egress traffic.\nIf Ports is not set then the rule does not filter traffic via port.\n\n+optional\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Ports allows for matching traffic based on port and protocols. This field is a list of destination ports for the outgoing egress traffic. If Ports is not set then the rule does not filter traffic via port."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyEgressRule describes an action to take on a particular\nset of traffic originating from pods selected by a AdminNetworkPolicy's\nSubject field.\n\u003cnetwork-policy-api:experimental:validation\u003e\n+kubebuilder:validation:XValidation:rule=\"!(self.to.exists(peer, has(peer.networks) || has(peer.nodes) || has(peer.domainNames)) \u0026\u0026 has(self.ports) \u0026\u0026 self.ports.exists(port, has(port.namedPort)))\",message=\"networks/nodes/domainNames peer cannot be set with namedPorts since there are no namedPorts for networks/nodes/domainNames\"","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyEgressRule describes an action to take on a particular set of traffic originating from pods selected by a AdminNetworkPolicy's Subject field. \u003cnetwork-policy-api:experimental:validation\u003e"]},{"type":"d","content":["+kubebuilder:validation:XValidation:rule=\"!(self.to.exists(peer, has(peer.networks) || has(peer.nodes) || has(peer.domainNames)) \u0026\u0026 has(self.ports) \u0026\u0026 self.ports.exists(port, has(port.namedPort)))\",message=\"networks/nodes/domainNames peer cannot be set with namedPorts since there are no namedPorts for networks/nodes/domainNames\""]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyIngressPeer":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyIngressPeer","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces defines a way to select all pods within a set of Namespaces.\nNote that host-networked pods are not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces defines a way to select all pods within a set of Namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr"],"docString":"Pods defines a way to select a set of pods in\na set of namespaces. Note that host-networked pods\nare not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods defines a way to select a set of pods in a set of namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyIngressPeer defines a peer to allow traffic to.\n\nExactly one of the fields must be set for a given peer and this is enforced\nby the validation rules on the CRD. If an implementation sees no fields are\nset then it can infer that the deployed CRD is of an incompatible version\nwith an unknown field.  In that case it should fail closed.\n\nFor \"Allow\" rules, \"fail closed\" means: \"treat the rule as matching no\ntraffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule\nas a 'Deny all' rule\".\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyIngressPeer defines a peer to allow traffic to."]},{"type":"p","content":["Exactly one of the fields must be set for a given peer and this is enforced by the validation rules on the CRD. If an implementation sees no fields are set then it can infer that the deployed CRD is of an incompatible version with an unknown field.  In that case it should fail closed."]},{"type":"p","content":["For \"Allow\" rules, \"fail closed\" means: \"treat the rule as matching no traffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule as a 'Deny all' rule\"."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyIngressRule":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyIngressRule","fields":[{"fieldName":"Name","typeName":"string","package":"","typeDecorators":null,"docString":"Name is an identifier for this rule, that may be no more than 100 characters\nin length. This field should be used by the implementation to help\nimprove observability, readability and error-reporting for any applied\nAdminNetworkPolicies.\n\n+optional\n+kubebuilder:validation:MaxLength=100","parsedDocString":{"elements":[{"type":"p","content":["Name is an identifier for this rule, that may be no more than 100 characters in length. This field should be used by the implementation to help improve observability, readability and error-reporting for any applied AdminNetworkPolicies."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxLength=100"]}]}},{"fieldName":"Action","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyRuleAction","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Action specifies the effect this rule will have on matching traffic.\nCurrently the following actions are supported:\nAllow: allows the selected traffic (even if it would otherwise have been denied by NetworkPolicy)\nDeny: denies the selected traffic\nPass: instructs the selected traffic to skip any remaining ANP rules, and\nthen pass execution to any NetworkPolicies that select the pod.\nIf the pod is not selected by any NetworkPolicies then execution\nis passed to any BaselineAdminNetworkPolicies that select the pod.","parsedDocString":{"elements":[{"type":"p","content":["Action specifies the effect this rule will have on matching traffic. Currently the following actions are supported: Allow: allows the selected traffic (even if it would otherwise have been denied by NetworkPolicy) Deny: denies the selected traffic Pass: instructs the selected traffic to skip any remaining ANP rules, and then pass execution to any NetworkPolicies that select the pod. If the pod is not selected by any NetworkPolicies then execution is passed to any BaselineAdminNetworkPolicies that select the pod."]}]}},{"fieldName":"From","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyIngressPeer","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"From is the list of sources whose traffic this rule applies to.\nIf any element matches the source of incoming\ntraffic then the specified action is applied.\nThis field must be defined and contain at least one item.\n\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["From is the list of sources whose traffic this rule applies to. If any element matches the source of incoming traffic then the specified action is applied. This field must be defined and contain at least one item."]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}},{"fieldName":"Ports","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyPort","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr","List"],"docString":"Ports allows for matching traffic based on port and protocols.\nThis field is a list of ports which should be matched on\nthe pods selected for this policy i.e the subject of the policy.\nSo it matches on the destination port for the ingress traffic.\nIf Ports is not set then the rule does not filter traffic via port.\n\n+optional\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Ports allows for matching traffic based on port and protocols. This field is a list of ports which should be matched on the pods selected for this policy i.e the subject of the policy. So it matches on the destination port for the ingress traffic. If Ports is not set then the rule does not filter traffic via port."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyIngressRule describes an action to take on a particular\nset of traffic destined for pods selected by an AdminNetworkPolicy's\nSubject field.","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyIngressRule describes an action to take on a particular set of traffic destined for pods selected by an AdminNetworkPolicy's Subject field."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyList":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyList","fields":[{"fieldName":"TypeMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.TypeMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"ListMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.ListMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"Items","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicy","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"","parsedDocString":{"elements":null}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyList contains a list of AdminNetworkPolicy","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyList contains a list of AdminNetworkPolicy"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyPort":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyPort","fields":[{"fieldName":"PortNumber","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.Port","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr"],"docString":"Port selects a port on a pod(s) based on number.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Port selects a port on a pod(s) based on number."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"NamedPort","typeName":"string","package":"","typeDecorators":["Ptr"],"docString":"NamedPort selects a port on a pod(s) based on name.\n\n\u003cnetwork-policy-api:experimental\u003e\n+optional","parsedDocString":{"elements":[{"type":"p","content":["NamedPort selects a port on a pod(s) based on name."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental\u003e"]},{"type":"d","content":["+optional"]}]}},{"fieldName":"PortRange","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.PortRange","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr"],"docString":"PortRange selects a port range on a pod(s) based on provided start and end\nvalues.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["PortRange selects a port range on a pod(s) based on provided start and end values."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyPort describes how to select network ports on pod(s).\nExactly one field must be set.\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyPort describes how to select network ports on pod(s). Exactly one field must be set."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyRuleAction":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyRuleAction","fields":[],"enumValues":[{"name":"AdminNetworkPolicyRuleActionAllow","docString":"AdminNetworkPolicyRuleActionAllow indicates that matching traffic will be\nallowed regardless of NetworkPolicy and BaselineAdminNetworkPolicy\nrules. Users cannot block traffic which has been matched by an \"Allow\"\nrule in an AdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyRuleActionAllow indicates that matching traffic will be allowed regardless of NetworkPolicy and BaselineAdminNetworkPolicy rules. Users cannot block traffic which has been matched by an \"Allow\" rule in an AdminNetworkPolicy."]}]}},{"name":"AdminNetworkPolicyRuleActionDeny","docString":"AdminNetworkPolicyRuleActionDeny indicates that matching traffic will be\ndenied before being checked against NetworkPolicy or\nBaselineAdminNetworkPolicy rules. Pods will never receive traffic which\nhas been matched by a \"Deny\" rule in an AdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyRuleActionDeny indicates that matching traffic will be denied before being checked against NetworkPolicy or BaselineAdminNetworkPolicy rules. Pods will never receive traffic which has been matched by a \"Deny\" rule in an AdminNetworkPolicy."]}]}},{"name":"AdminNetworkPolicyRuleActionPass","docString":"AdminNetworkPolicyRuleActionPass indicates that matching traffic will\nbypass further AdminNetworkPolicy processing (ignoring rules with lower\nprecedence) and be allowed or denied based on NetworkPolicy and\nBaselineAdminNetworkPolicy rules.","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyRuleActionPass indicates that matching traffic will bypass further AdminNetworkPolicy processing (ignoring rules with lower precedence) and be allowed or denied based on NetworkPolicy and BaselineAdminNetworkPolicy rules."]}]}}],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyRuleAction string describes the AdminNetworkPolicy action type.\n\n+enum\n+kubebuilder:validation:Enum={\"Allow\", \"Deny\", \"Pass\"}","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyRuleAction string describes the AdminNetworkPolicy action type."]},{"type":"d","content":["+enum"]},{"type":"d","content":["+kubebuilder:validation:Enum={\"Allow\", \"Deny\", \"Pass\"}"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicySpec":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicySpec","fields":[{"fieldName":"Priority","typeName":"int32","package":"","typeDecorators":null,"docString":"Priority is a value from 0 to 1000. Policies with lower priority values have\nhigher precedence, and are checked before policies with higher priority values.\nAll AdminNetworkPolicy rules have higher precedence than NetworkPolicy or\nBaselineAdminNetworkPolicy rules.\nIf two (or more) policies with the same priority could both match a connection,\nthen the implementation can apply any of the matching policies to the\nconnection, and there is no way for the user to reliably determine which one it\nwill choose. Administrators must be careful about assigning the priorities for\npolicies with rules that will match many connections, and ensure that policies\nhave unique priority values in cases where ambiguity would be unacceptable.\n\n+kubebuilder:validation:Minimum=0\n+kubebuilder:validation:Maximum=1000","parsedDocString":{"elements":[{"type":"p","content":["Priority is a value from 0 to 1000. Policies with lower priority values have higher precedence, and are checked before policies with higher priority values. All AdminNetworkPolicy rules have higher precedence than NetworkPolicy or BaselineAdminNetworkPolicy rules. If two (or more) policies with the same priority could both match a connection, then the implementation can apply any of the matching policies to the connection, and there is no way for the user to reliably determine which one it will choose. Administrators must be careful about assigning the priorities for policies with rules that will match many connections, and ensure that policies have unique priority values in cases where ambiguity would be unacceptable."]},{"type":"d","content":["+kubebuilder:validation:Minimum=0"]},{"type":"d","content":["+kubebuilder:validation:Maximum=1000"]}]}},{"fieldName":"Subject","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicySubject","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Subject defines the pods to which this AdminNetworkPolicy applies.\nNote that host-networked pods are not included in subject selection.","parsedDocString":{"elements":[{"type":"p","content":["Subject defines the pods to which this AdminNetworkPolicy applies. Note that host-networked pods are not included in subject selection."]}]}},{"fieldName":"Ingress","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyIngressRule","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"Ingress is the list of Ingress rules to be applied to the selected pods.\nA total of 100 rules will be allowed in each ANP instance.\nThe relative precedence of ingress rules within a single ANP object (all of\nwhich share the priority) will be determined by the order in which the rule\nis written. Thus, a rule that appears at the top of the ingress rules\nwould take the highest precedence.\nANPs with no ingress rules do not affect ingress traffic.\n\n+optional\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Ingress is the list of Ingress rules to be applied to the selected pods. A total of 100 rules will be allowed in each ANP instance. The relative precedence of ingress rules within a single ANP object (all of which share the priority) will be determined by the order in which the rule is written. Thus, a rule that appears at the top of the ingress rules would take the highest precedence. ANPs with no ingress rules do not affect ingress traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}},{"fieldName":"Egress","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyEgressRule","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"Egress is the list of Egress rules to be applied to the selected pods.\nA total of 100 rules will be allowed in each ANP instance.\nThe relative precedence of egress rules within a single ANP object (all of\nwhich share the priority) will be determined by the order in which the rule\nis written. Thus, a rule that appears at the top of the egress rules\nwould take the highest precedence.\nANPs with no egress rules do not affect egress traffic.\n\n+optional\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Egress is the list of Egress rules to be applied to the selected pods. A total of 100 rules will be allowed in each ANP instance. The relative precedence of egress rules within a single ANP object (all of which share the priority) will be determined by the order in which the rule is written. Thus, a rule that appears at the top of the egress rules would take the highest precedence. ANPs with no egress rules do not affect egress traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicySpec defines the desired state of AdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicySpec defines the desired state of AdminNetworkPolicy."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyStatus":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicyStatus","fields":[{"fieldName":"Conditions","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.Condition","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["List"],"docString":"+patchMergeKey=type\n+patchStrategy=merge\n+listType=map\n+listMapKey=type","parsedDocString":{"elements":[{"type":"d","content":["+patchMergeKey=type"]},{"type":"d","content":["+patchStrategy=merge"]},{"type":"d","content":["+listType=map"]},{"type":"d","content":["+listMapKey=type"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicyStatus defines the observed state of AdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicyStatus defines the observed state of AdminNetworkPolicy."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicySubject":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"AdminNetworkPolicySubject","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces is used to select pods via namespace selectors.\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces is used to select pods via namespace selectors."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr"],"docString":"Pods is used to select pods via namespace AND pod selectors.\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods is used to select pods via namespace AND pod selectors."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"AdminNetworkPolicySubject defines what resources the policy applies to.\nExactly one field must be set.\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["AdminNetworkPolicySubject defines what resources the policy applies to. Exactly one field must be set."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicy":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicy","fields":[{"fieldName":"TypeMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.TypeMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"ObjectMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.ObjectMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"Spec","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicySpec","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Specification of the desired behavior of BaselineAdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["Specification of the desired behavior of BaselineAdminNetworkPolicy."]}]}},{"fieldName":"Status","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyStatus","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Status is the status to be reported by the implementation.\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Status is the status to be reported by the implementation."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":true,"isTopLevel":true,"docString":"+genclient\n+genclient:nonNamespaced\n+kubebuilder:object:root=true\n+kubebuilder:subresource:status\n+kubebuilder:resource:shortName=banp,scope=Cluster\n+kubebuilder:printcolumn:name=\"Age\",type=\"date\",JSONPath=\".metadata.creationTimestamp\"\n+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object\n+kubebuilder:validation:XValidation:rule=\"self.metadata.name == 'default'\",message=\"Only one baseline admin network policy with metadata.name=\\\"default\\\" can be created in the cluster\"\nBaselineAdminNetworkPolicy is a cluster level resource that is part of the\nAdminNetworkPolicy API.","parsedDocString":{"elements":[{"type":"d","content":["+genclient"]},{"type":"d","content":["+genclient:nonNamespaced"]},{"type":"d","content":["+kubebuilder:object:root=true"]},{"type":"d","content":["+kubebuilder:subresource:status"]},{"type":"d","content":["+kubebuilder:resource:shortName=banp,scope=Cluster"]},{"type":"d","content":["+kubebuilder:printcolumn:name=\"Age\",type=\"date\",JSONPath=\".metadata.creationTimestamp\""]},{"type":"d","content":["+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object"]},{"type":"d","content":["+kubebuilder:validation:XValidation:rule=\"self.metadata.name == 'default'\",message=\"Only one baseline admin network policy with metadata.name=\\\"default\\\" can be created in the cluster\""]},{"type":"p","content":["BaselineAdminNetworkPolicy is a cluster level resource that is part of the AdminNetworkPolicy API."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyEgressPeer":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicyEgressPeer","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces defines a way to select all pods within a set of Namespaces.\nNote that host-networked pods are not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces defines a way to select all pods within a set of Namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr"],"docString":"Pods defines a way to select a set of pods in\na set of namespaces. Note that host-networked pods\nare not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods defines a way to select a set of pods in a set of namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Nodes","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Nodes defines a way to select a set of nodes in\nthe cluster (based on the node's labels). It selects\nthe nodeIPs as the peer type by matching on the IPs\npresent in the node.Status.Addresses field of the node.\nThis field follows standard label selector\nsemantics; if present but empty, it selects all Nodes.\n\n\u003cnetwork-policy-api:experimental\u003e\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Nodes defines a way to select a set of nodes in the cluster (based on the node's labels). It selects the nodeIPs as the peer type by matching on the IPs present in the node.Status.Addresses field of the node. This field follows standard label selector semantics; if present but empty, it selects all Nodes."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental\u003e"]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Networks","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.CIDR","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"Networks defines a way to select peers via CIDR blocks.\nThis is intended for representing entities that live outside the cluster,\nwhich can't be selected by pods, namespaces and nodes peers, but note\nthat cluster-internal traffic will be checked against the rule as\nwell. So if you Allow or Deny traffic to `\"0.0.0.0/0\"`, that will allow\nor deny all IPv4 pod-to-pod traffic as well. If you don't want that,\nadd a rule that Passes all pod traffic before the Networks rule.\n\nEach item in Networks should be provided in the CIDR format and should be\nIPv4 or IPv6, for example \"10.0.0.0/8\" or \"fd00::/8\".\n\nNetworks can have upto 25 CIDRs specified.\n\n+optional\n+listType=set\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Networks defines a way to select peers via CIDR blocks. This is intended for representing entities that live outside the cluster, which can't be selected by pods, namespaces and nodes peers, but note that cluster-internal traffic will be checked against the rule as well. So if you Allow or Deny traffic to `\"0.0.0.0/0\"`, that will allow or deny all IPv4 pod-to-pod traffic as well. If you don't want that, add a rule that Passes all pod traffic before the Networks rule."]},{"type":"p","content":["Each item in Networks should be provided in the CIDR format and should be IPv4 or IPv6, for example \"10.0.0.0/8\" or \"fd00::/8\"."]},{"type":"p","content":["Networks can have upto 25 CIDRs specified."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+listType=set"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicyEgressPeer defines a peer to allow traffic to.\n\nExactly one of the fields must be set for a given peer and this is enforced\nby the validation rules on the CRD. If an implementation sees no fields are\nset then it can infer that the deployed CRD is of an incompatible version\nwith an unknown field.  In that case it should fail closed.\n\nFor \"Allow\" rules, \"fail closed\" means: \"treat the rule as matching no\ntraffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule\nas a 'Deny all' rule\".\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyEgressPeer defines a peer to allow traffic to."]},{"type":"p","content":["Exactly one of the fields must be set for a given peer and this is enforced by the validation rules on the CRD. If an implementation sees no fields are set then it can infer that the deployed CRD is of an incompatible version with an unknown field.  In that case it should fail closed."]},{"type":"p","content":["For \"Allow\" rules, \"fail closed\" means: \"treat the rule as matching no traffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule as a 'Deny all' rule\"."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyEgressRule":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicyEgressRule","fields":[{"fieldName":"Name","typeName":"string","package":"","typeDecorators":null,"docString":"Name is an identifier for this rule, that may be no more than 100 characters\nin length. This field should be used by the implementation to help\nimprove observability, readability and error-reporting for any applied\nBaselineAdminNetworkPolicies.\n\n+optional\n+kubebuilder:validation:MaxLength=100","parsedDocString":{"elements":[{"type":"p","content":["Name is an identifier for this rule, that may be no more than 100 characters in length. This field should be used by the implementation to help improve observability, readability and error-reporting for any applied BaselineAdminNetworkPolicies."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxLength=100"]}]}},{"fieldName":"Action","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyRuleAction","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Action specifies the effect this rule will have on matching traffic.\nCurrently the following actions are supported:\nAllow: allows the selected traffic\nDeny: denies the selected traffic","parsedDocString":{"elements":[{"type":"p","content":["Action specifies the effect this rule will have on matching traffic. Currently the following actions are supported: Allow: allows the selected traffic Deny: denies the selected traffic"]}]}},{"fieldName":"To","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyEgressPeer","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"To is the list of destinations whose traffic this rule applies to.\nIf any element matches the destination of outgoing\ntraffic then the specified action is applied.\nThis field must be defined and contain at least one item.\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["To is the list of destinations whose traffic this rule applies to. If any element matches the destination of outgoing traffic then the specified action is applied. This field must be defined and contain at least one item."]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}},{"fieldName":"Ports","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyPort","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr","List"],"docString":"Ports allows for matching traffic based on port and protocols.\nThis field is a list of destination ports for the outgoing egress traffic.\nIf Ports is not set then the rule does not filter traffic via port.\n+optional\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Ports allows for matching traffic based on port and protocols. This field is a list of destination ports for the outgoing egress traffic. If Ports is not set then the rule does not filter traffic via port."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicyEgressRule describes an action to take on a particular\nset of traffic originating from pods selected by a BaselineAdminNetworkPolicy's\nSubject field.\n\u003cnetwork-policy-api:experimental:validation\u003e\n+kubebuilder:validation:XValidation:rule=\"!(self.to.exists(peer, has(peer.networks) || has(peer.nodes)) \u0026\u0026 has(self.ports) \u0026\u0026 self.ports.exists(port, has(port.namedPort)))\",message=\"networks/nodes peer cannot be set with namedPorts since there are no namedPorts for networks/nodes\"","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyEgressRule describes an action to take on a particular set of traffic originating from pods selected by a BaselineAdminNetworkPolicy's Subject field. \u003cnetwork-policy-api:experimental:validation\u003e"]},{"type":"d","content":["+kubebuilder:validation:XValidation:rule=\"!(self.to.exists(peer, has(peer.networks) || has(peer.nodes)) \u0026\u0026 has(self.ports) \u0026\u0026 self.ports.exists(port, has(port.namedPort)))\",message=\"networks/nodes peer cannot be set with namedPorts since there are no namedPorts for networks/nodes\""]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyIngressRule":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicyIngressRule","fields":[{"fieldName":"Name","typeName":"string","package":"","typeDecorators":null,"docString":"Name is an identifier for this rule, that may be no more than 100 characters\nin length. This field should be used by the implementation to help\nimprove observability, readability and error-reporting for any applied\nBaselineAdminNetworkPolicies.\n\n+optional\n+kubebuilder:validation:MaxLength=100","parsedDocString":{"elements":[{"type":"p","content":["Name is an identifier for this rule, that may be no more than 100 characters in length. This field should be used by the implementation to help improve observability, readability and error-reporting for any applied BaselineAdminNetworkPolicies."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxLength=100"]}]}},{"fieldName":"Action","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyRuleAction","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Action specifies the effect this rule will have on matching traffic.\nCurrently the following actions are supported:\nAllow: allows the selected traffic\nDeny: denies the selected traffic","parsedDocString":{"elements":[{"type":"p","content":["Action specifies the effect this rule will have on matching traffic. Currently the following actions are supported: Allow: allows the selected traffic Deny: denies the selected traffic"]}]}},{"fieldName":"From","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyIngressPeer","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"From is the list of sources whose traffic this rule applies to.\nIf any element matches the source of incoming\ntraffic then the specified action is applied.\nThis field must be defined and contain at least one item.\n\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["From is the list of sources whose traffic this rule applies to. If any element matches the source of incoming traffic then the specified action is applied. This field must be defined and contain at least one item."]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}},{"fieldName":"Ports","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicyPort","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["Ptr","List"],"docString":"Ports allows for matching traffic based on port and protocols.\nThis field is a list of ports which should be matched on\nthe pods selected for this policy i.e the subject of the policy.\nSo it matches on the destination port for the ingress traffic.\nIf Ports is not set then the rule does not filter traffic via port.\n\n+optional\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Ports allows for matching traffic based on port and protocols. This field is a list of ports which should be matched on the pods selected for this policy i.e the subject of the policy. So it matches on the destination port for the ingress traffic. If Ports is not set then the rule does not filter traffic via port."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicyIngressRule describes an action to take on a particular\nset of traffic destined for pods selected by a BaselineAdminNetworkPolicy's\nSubject field.","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyIngressRule describes an action to take on a particular set of traffic destined for pods selected by a BaselineAdminNetworkPolicy's Subject field."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyList":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicyList","fields":[{"fieldName":"TypeMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.TypeMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"ListMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.ListMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"Items","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicy","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"","parsedDocString":{"elements":null}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicyList contains a list of BaselineAdminNetworkPolicy","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyList contains a list of BaselineAdminNetworkPolicy"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyRuleAction":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicyRuleAction","fields":[],"enumValues":[{"name":"BaselineAdminNetworkPolicyRuleActionDeny","docString":"BaselineAdminNetworkPolicyRuleActionDeny enables admins to deny traffic.","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyRuleActionDeny enables admins to deny traffic."]}]}},{"name":"BaselineAdminNetworkPolicyRuleActionAllow","docString":"BaselineAdminNetworkPolicyRuleActionAllow enables admins to allow certain traffic.","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyRuleActionAllow enables admins to allow certain traffic."]}]}}],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicyRuleAction string describes the BaselineAdminNetworkPolicy\naction type.\n\n+enum\n+kubebuilder:validation:Enum={\"Allow\", \"Deny\"}","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyRuleAction string describes the BaselineAdminNetworkPolicy action type."]},{"type":"d","content":["+enum"]},{"type":"d","content":["+kubebuilder:validation:Enum={\"Allow\", \"Deny\"}"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicySpec":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicySpec","fields":[{"fieldName":"Subject","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.AdminNetworkPolicySubject","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":null,"docString":"Subject defines the pods to which this BaselineAdminNetworkPolicy applies.\nNote that host-networked pods are not included in subject selection.","parsedDocString":{"elements":[{"type":"p","content":["Subject defines the pods to which this BaselineAdminNetworkPolicy applies. Note that host-networked pods are not included in subject selection."]}]}},{"fieldName":"Ingress","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyIngressRule","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"Ingress is the list of Ingress rules to be applied to the selected pods\nif they are not matched by any AdminNetworkPolicy or NetworkPolicy rules.\nA total of 100 Ingress rules will be allowed in each BANP instance.\nThe relative precedence of ingress rules within a single BANP object\nwill be determined by the order in which the rule is written.\nThus, a rule that appears at the top of the ingress rules\nwould take the highest precedence.\nBANPs with no ingress rules do not affect ingress traffic.\n\n+optional\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Ingress is the list of Ingress rules to be applied to the selected pods if they are not matched by any AdminNetworkPolicy or NetworkPolicy rules. A total of 100 Ingress rules will be allowed in each BANP instance. The relative precedence of ingress rules within a single BANP object will be determined by the order in which the rule is written. Thus, a rule that appears at the top of the ingress rules would take the highest precedence. BANPs with no ingress rules do not affect ingress traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}},{"fieldName":"Egress","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyEgressRule","package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeDecorators":["List"],"docString":"Egress is the list of Egress rules to be applied to the selected pods if\nthey are not matched by any AdminNetworkPolicy or NetworkPolicy rules.\nA total of 100 Egress rules will be allowed in each BANP instance.\nThe relative precedence of egress rules within a single BANP object\nwill be determined by the order in which the rule is written.\nThus, a rule that appears at the top of the egress rules\nwould take the highest precedence.\nBANPs with no egress rules do not affect egress traffic.\n\n+optional\n+kubebuilder:validation:MaxItems=100","parsedDocString":{"elements":[{"type":"p","content":["Egress is the list of Egress rules to be applied to the selected pods if they are not matched by any AdminNetworkPolicy or NetworkPolicy rules. A total of 100 Egress rules will be allowed in each BANP instance. The relative precedence of egress rules within a single BANP object will be determined by the order in which the rule is written. Thus, a rule that appears at the top of the egress rules would take the highest precedence. BANPs with no egress rules do not affect egress traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=100"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicySpec defines the desired state of\nBaselineAdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicySpec defines the desired state of BaselineAdminNetworkPolicy."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.BaselineAdminNetworkPolicyStatus":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"BaselineAdminNetworkPolicyStatus","fields":[{"fieldName":"Conditions","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.Condition","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["List"],"docString":"+patchMergeKey=type\n+patchStrategy=merge\n+listType=map\n+listMapKey=type","parsedDocString":{"elements":[{"type":"d","content":["+patchMergeKey=type"]},{"type":"d","content":["+patchStrategy=merge"]},{"type":"d","content":["+listType=map"]},{"type":"d","content":["+listMapKey=type"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"BaselineAdminNetworkPolicyStatus defines the observed state of\nBaselineAdminNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["BaselineAdminNetworkPolicyStatus defines the observed state of BaselineAdminNetworkPolicy."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.NamespacedPod":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"NamespacedPod","fields":[{"fieldName":"NamespaceSelector","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"NamespaceSelector follows standard label selector semantics; if empty,\nit selects all Namespaces.","parsedDocString":{"elements":[{"type":"p","content":["NamespaceSelector follows standard label selector semantics; if empty, it selects all Namespaces."]}]}},{"fieldName":"PodSelector","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"PodSelector is used to explicitly select pods within a namespace; if empty,\nit selects all Pods.","parsedDocString":{"elements":[{"type":"p","content":["PodSelector is used to explicitly select pods within a namespace; if empty, it selects all Pods."]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"NamespacedPod allows the user to select a given set of pod(s) in\nselected namespace(s).","parsedDocString":{"elements":[{"type":"p","content":["NamespacedPod allows the user to select a given set of pod(s) in selected namespace(s)."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.Port":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"Port","fields":[{"fieldName":"Protocol","typeName":"k8s.io/api/core/v1.Protocol","package":"k8s.io/api/core/v1","typeDecorators":null,"docString":"Protocol is the network protocol (TCP, UDP, or SCTP) which traffic must\nmatch. If not specified, this field defaults to TCP.\n+kubebuilder:default=TCP","parsedDocString":{"elements":[{"type":"p","content":["Protocol is the network protocol (TCP, UDP, or SCTP) which traffic must match. If not specified, this field defaults to TCP."]},{"type":"d","content":["+kubebuilder:default=TCP"]}]}},{"fieldName":"Port","typeName":"int32","package":"","typeDecorators":null,"docString":"Number defines a network port value.\n+kubebuilder:validation:Minimum=1\n+kubebuilder:validation:Maximum=65535","parsedDocString":{"elements":[{"type":"p","content":["Number defines a network port value."]},{"type":"d","content":["+kubebuilder:validation:Minimum=1"]},{"type":"d","content":["+kubebuilder:validation:Maximum=65535"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"","parsedDocString":{"elements":null}},"sigs.k8s.io/network-policy-api/apis/v1alpha1.PortRange":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha1","typeName":"PortRange","fields":[{"fieldName":"Protocol","typeName":"k8s.io/api/core/v1.Protocol","package":"k8s.io/api/core/v1","typeDecorators":null,"docString":"Protocol is the network protocol (TCP, UDP, or SCTP) which traffic must\nmatch. If not specified, this field defaults to TCP.\n+kubebuilder:default=TCP","parsedDocString":{"elements":[{"type":"p","content":["Protocol is the network protocol (TCP, UDP, or SCTP) which traffic must match. If not specified, this field defaults to TCP."]},{"type":"d","content":["+kubebuilder:default=TCP"]}]}},{"fieldName":"Start","typeName":"int32","package":"","typeDecorators":null,"docString":"Start defines a network port that is the start of a port range, the Start\nvalue must be less than End.\n+kubebuilder:validation:Minimum=1\n+kubebuilder:validation:Maximum=65535","parsedDocString":{"elements":[{"type":"p","content":["Start defines a network port that is the start of a port range, the Start value must be less than End."]},{"type":"d","content":["+kubebuilder:validation:Minimum=1"]},{"type":"d","content":["+kubebuilder:validation:Maximum=65535"]}]}},{"fieldName":"End","typeName":"int32","package":"","typeDecorators":null,"docString":"End defines a network port that is the end of a port range, the End value\nmust be greater than Start.\n+kubebuilder:validation:Minimum=1\n+kubebuilder:validation:Maximum=65535","parsedDocString":{"elements":[{"type":"p","content":["End defines a network port that is the end of a port range, the End value must be greater than Start."]},{"type":"d","content":["+kubebuilder:validation:Minimum=1"]},{"type":"d","content":["+kubebuilder:validation:Maximum=65535"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"PortRange defines an inclusive range of ports from the the assigned Start value\nto End value.","parsedDocString":{"elements":[{"type":"p","content":["PortRange defines an inclusive range of ports from the the assigned Start value to End value."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicy":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicy","fields":[{"fieldName":"TypeMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.TypeMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"ObjectMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.ObjectMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"Spec","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicySpec","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":null,"docString":"Spec defines the desired behavior of ClusterNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["Spec defines the desired behavior of ClusterNetworkPolicy."]}]}},{"fieldName":"Status","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyStatus","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":null,"docString":"Status is the status to be reported by the implementation.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Status is the status to be reported by the implementation."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":true,"isTopLevel":true,"docString":"ClusterNetworkPolicy is a cluster-wide network policy resource.\n\n+genclient\n+genclient:nonNamespaced\n+kubebuilder:object:root=true\n+kubebuilder:subresource:status\n+kubebuilder:resource:shortName=cnp,scope=Cluster\n+kubebuilder:printcolumn:name=\"Tier\",type=string,JSONPath=\".spec.tier\"\n+kubebuilder:printcolumn:name=\"Priority\",type=string,JSONPath=\".spec.priority\"\n+kubebuilder:printcolumn:name=\"Age\",type=\"date\",JSONPath=\".metadata.creationTimestamp\"\n+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicy is a cluster-wide network policy resource."]},{"type":"d","content":["+genclient"]},{"type":"d","content":["+genclient:nonNamespaced"]},{"type":"d","content":["+kubebuilder:object:root=true"]},{"type":"d","content":["+kubebuilder:subresource:status"]},{"type":"d","content":["+kubebuilder:resource:shortName=cnp,scope=Cluster"]},{"type":"d","content":["+kubebuilder:printcolumn:name=\"Tier\",type=string,JSONPath=\".spec.tier\""]},{"type":"d","content":["+kubebuilder:printcolumn:name=\"Priority\",type=string,JSONPath=\".spec.priority\""]},{"type":"d","content":["+kubebuilder:printcolumn:name=\"Age\",type=\"date\",JSONPath=\".metadata.creationTimestamp\""]},{"type":"d","content":["+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyEgressPeer":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyEgressPeer","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces defines a way to select all pods within a set of Namespaces.\nNote that host-networked pods are not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces defines a way to select all pods within a set of Namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"Pods defines a way to select a set of pods in\na set of namespaces. Note that host-networked pods\nare not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods defines a way to select a set of pods in a set of namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Nodes","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Nodes defines a way to select a set of nodes in\nthe cluster (based on the node's labels). It selects\nthe nodeIPs as the peer type by matching on the IPs\npresent in the node.Status.Addresses field of the node.\nThis field follows standard label selector\nsemantics; if present but empty, it selects all Nodes.\n\n\u003cnetwork-policy-api:experimental\u003e\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Nodes defines a way to select a set of nodes in the cluster (based on the node's labels). It selects the nodeIPs as the peer type by matching on the IPs present in the node.Status.Addresses field of the node. This field follows standard label selector semantics; if present but empty, it selects all Nodes."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental\u003e"]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Networks","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.CIDR","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"Networks defines a way to select peers via CIDR blocks.\nThis is intended for representing entities that live outside the cluster,\nwhich can't be selected by pods, namespaces and nodes peers, but note\nthat cluster-internal traffic will be checked against the rule as\nwell. So if you Accept or Deny traffic to `\"0.0.0.0/0\"`, that will allow\nor deny all IPv4 pod-to-pod traffic as well. If you don't want that,\nadd a rule that Passes all pod traffic before the Networks rule.\n\nEach item in Networks should be provided in the CIDR format and should be\nIPv4 or IPv6, for example \"10.0.0.0/8\" or \"fd00::/8\".\n\nNetworks can have up to 25 CIDRs specified.\n\n+optional\n+listType=set\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Networks defines a way to select peers via CIDR blocks. This is intended for representing entities that live outside the cluster, which can't be selected by pods, namespaces and nodes peers, but note that cluster-internal traffic will be checked against the rule as well. So if you Accept or Deny traffic to `\"0.0.0.0/0\"`, that will allow or deny all IPv4 pod-to-pod traffic as well. If you don't want that, add a rule that Passes all pod traffic before the Networks rule."]},{"type":"p","content":["Each item in Networks should be provided in the CIDR format and should be IPv4 or IPv6, for example \"10.0.0.0/8\" or \"fd00::/8\"."]},{"type":"p","content":["Networks can have up to 25 CIDRs specified."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+listType=set"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}},{"fieldName":"DomainNames","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.DomainName","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"DomainNames provides a way to specify domain names as peers.\n\nDomainNames is only supported for Accept rules. In order to control\naccess, DomainNames Accept rules should be used with a lower precedence\negress deny -- this allows the admin to maintain an explicit \"allowlist\"\nof reachable domains.\n\nDomainNames can have up to 25 domain names specified in one rule.\n\n\u003cnetwork-policy-api:experimental\u003e\n\n+optional\n+listType=set\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["DomainNames provides a way to specify domain names as peers."]},{"type":"p","content":["DomainNames is only supported for Accept rules. In order to control access, DomainNames Accept rules should be used with a lower precedence egress deny -- this allows the admin to maintain an explicit \"allowlist\" of reachable domains."]},{"type":"p","content":["DomainNames can have up to 25 domain names specified in one rule."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental\u003e"]},{"type":"d","content":["+optional"]},{"type":"d","content":["+listType=set"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyEgressPeer defines a peer to allow traffic to.\n\nExactly one of the fields must be set for a given peer and this is enforced\nby the validation rules on the CRD. If an implementation sees no fields are\nset then it can infer that the deployed CRD is of an incompatible version\nwith an unknown field.  In that case it should fail closed.\n\nFor \"Accept\" rules, \"fail closed\" means: \"treat the rule as matching no\ntraffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule\nas a 'Deny all' rule\".\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyEgressPeer defines a peer to allow traffic to."]},{"type":"p","content":["Exactly one of the fields must be set for a given peer and this is enforced by the validation rules on the CRD. If an implementation sees no fields are set then it can infer that the deployed CRD is of an incompatible version with an unknown field.  In that case it should fail closed."]},{"type":"p","content":["For \"Accept\" rules, \"fail closed\" means: \"treat the rule as matching no traffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule as a 'Deny all' rule\"."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyEgressRule":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyEgressRule","fields":[{"fieldName":"Name","typeName":"string","package":"","typeDecorators":null,"docString":"Name is an identifier for this rule, that may be no more than\n100 characters in length. This field should be used by the implementation\nto help improve observability, readability and error-reporting\nfor any applied policies.\n\n+optional\n+kubebuilder:validation:MaxLength=100","parsedDocString":{"elements":[{"type":"p","content":["Name is an identifier for this rule, that may be no more than 100 characters in length. This field should be used by the implementation to help improve observability, readability and error-reporting for any applied policies."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxLength=100"]}]}},{"fieldName":"Action","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyRuleAction","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":null,"docString":"Action specifies the effect this rule will have on matching\ntraffic.  Currently the following actions are supported:\n\n- Accept: Accepts the selected traffic, allowing it to\n  egress. No further ClusterNetworkPolicy or NetworkPolicy\n  rules will be processed.\n\n- Deny: Drops the selected traffic. No further\n  ClusterNetworkPolicy or NetworkPolicy rules will be\n  processed.\n\n- Pass: Skips all further ClusterNetworkPolicy rules in the\n  current tier for the selected traffic, and passes\n  evaluation to the next tier.","parsedDocString":{"elements":[{"type":"p","content":["Action specifies the effect this rule will have on matching traffic.  Currently the following actions are supported:"]},{"type":"l","content":["Accept: Accepts the selected traffic, allowing it to","No further ClusterNetworkPolicy or NetworkPolicy"]},{"type":"c","content":["rules will be processed.\n"]},{"type":"l","content":["Deny: Drops the selected traffic. No further\nClusterNetworkPolicy or NetworkPolicy rules will be\nprocessed."]},{"type":"l","content":["Pass: Skips all further ClusterNetworkPolicy rules in the\ncurrent tier for the selected traffic, and passes\nevaluation to the next tier."]}]}},{"fieldName":"To","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyEgressPeer","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"To is the list of destinations whose traffic this rule applies to. If any\nelement matches the destination of outgoing traffic then the specified\naction is applied. This field must be defined and contain at least one\nitem.\n\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["To is the list of destinations whose traffic this rule applies to. If any element matches the destination of outgoing traffic then the specified action is applied. This field must be defined and contain at least one item."]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}},{"fieldName":"Protocols","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocol","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"Protocols allows for more fine-grain matching of traffic on\nprotocol-specific attributes such as the port. If\nunspecified, protocol-specific attributes will not be used\nto match traffic.\n\n+optional\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Protocols allows for more fine-grain matching of traffic on protocol-specific attributes such as the port. If unspecified, protocol-specific attributes will not be used to match traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyEgressRule describes an action to take on a particular\nset of traffic originating from pods selected by a ClusterNetworkPolicy's\nSubject field.\n\n\u003cnetwork-policy-api:experimental:validation\u003e\n+kubebuilder:validation:XValidation:rule=\"!(self.to.exists(peer, has(peer.networks) || has(peer.nodes) || has(peer.domainNames)) \u0026\u0026 has(self.protocols) \u0026\u0026 self.protocols.exists(protocol, has(protocol.destinationNamedPort)))\",message=\"networks/nodes/domainNames peer cannot be set with namedPorts since there are no namedPorts for networks/nodes/domainNames\"","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyEgressRule describes an action to take on a particular set of traffic originating from pods selected by a ClusterNetworkPolicy's Subject field."]},{"type":"p","content":["\u003cnetwork-policy-api:experimental:validation\u003e"]},{"type":"d","content":["+kubebuilder:validation:XValidation:rule=\"!(self.to.exists(peer, has(peer.networks) || has(peer.nodes) || has(peer.domainNames)) \u0026\u0026 has(self.protocols) \u0026\u0026 self.protocols.exists(protocol, has(protocol.destinationNamedPort)))\",message=\"networks/nodes/domainNames peer cannot be set with namedPorts since there are no namedPorts for networks/nodes/domainNames\""]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyIngressPeer":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyIngressPeer","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces defines a way to select all pods within a set of Namespaces.\nNote that host-networked pods are not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces defines a way to select all pods within a set of Namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"Pods defines a way to select a set of pods in\na set of namespaces. Note that host-networked pods\nare not included in this type of peer.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods defines a way to select a set of pods in a set of namespaces. Note that host-networked pods are not included in this type of peer."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyIngressPeer defines a peer to allow traffic from.\n\nExactly one of the fields must be set for a given peer and this is enforced\nby the validation rules on the CRD. If an implementation sees no fields are\nset then it can infer that the deployed CRD is of an incompatible version\nwith an unknown field.  In that case it should fail closed.\n\nFor \"Accept\" rules, \"fail closed\" means: \"treat the rule as matching no\ntraffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule\nas a 'Deny all' rule\".\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyIngressPeer defines a peer to allow traffic from."]},{"type":"p","content":["Exactly one of the fields must be set for a given peer and this is enforced by the validation rules on the CRD. If an implementation sees no fields are set then it can infer that the deployed CRD is of an incompatible version with an unknown field.  In that case it should fail closed."]},{"type":"p","content":["For \"Accept\" rules, \"fail closed\" means: \"treat the rule as matching no traffic\". For \"Deny\" and \"Pass\" rules, \"fail closed\" means: \"treat the rule as a 'Deny all' rule\"."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyIngressRule":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyIngressRule","fields":[{"fieldName":"Name","typeName":"string","package":"","typeDecorators":null,"docString":"Name is an identifier for this rule, that may be no more than\n100 characters in length. This field should be used by the implementation\nto help improve observability, readability and error-reporting\nfor any applied policies.\n\n+optional\n+kubebuilder:validation:MaxLength=100","parsedDocString":{"elements":[{"type":"p","content":["Name is an identifier for this rule, that may be no more than 100 characters in length. This field should be used by the implementation to help improve observability, readability and error-reporting for any applied policies."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxLength=100"]}]}},{"fieldName":"Action","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyRuleAction","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":null,"docString":"Action specifies the effect this rule will have on matching\ntraffic. Currently the following actions are supported:\n\n- Accept: Accepts the selected traffic, allowing it into\n  the destination. No further ClusterNetworkPolicy or\n  NetworkPolicy rules will be processed.\n\n  Note: while Accept ensures traffic is accepted by\n  Kubernetes network policy, it is still possible that the\n  packet is blocked in other ways: custom nftable rules,\n  high-layers e.g. service mesh.\n\n- Deny: Drops the selected traffic. No further\n  ClusterNetworkPolicy or NetworkPolicy rules will be\n  processed.\n\n- Pass: Skips all further ClusterNetworkPolicy rules in the\n  current tier for the selected traffic, and passes\n  evaluation to the next tier.","parsedDocString":{"elements":[{"type":"p","content":["Action specifies the effect this rule will have on matching traffic. Currently the following actions are supported:"]},{"type":"l","content":["Accept: Accepts the selected traffic, allowing it into\nthe destination. No further ClusterNetworkPolicy or\nNetworkPolicy rules will be processed."]},{"type":"c","content":["Note: while Accept ensures traffic is accepted by\nKubernetes network policy, it is still possible that the\npacket is blocked in other ways: custom nftable rules,\nhigh-layers e.g. service mesh.\n"]},{"type":"l","content":["Deny: Drops the selected traffic. No further\nClusterNetworkPolicy or NetworkPolicy rules will be\nprocessed."]},{"type":"l","content":["Pass: Skips all further ClusterNetworkPolicy rules in the\ncurrent tier for the selected traffic, and passes\nevaluation to the next tier."]}]}},{"fieldName":"From","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyIngressPeer","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"From is the list of sources whose traffic this rule applies to.\nIf any element matches the source of incoming\ntraffic then the specified action is applied.\nThis field must be defined and contain at least one item.\n\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["From is the list of sources whose traffic this rule applies to. If any element matches the source of incoming traffic then the specified action is applied. This field must be defined and contain at least one item."]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}},{"fieldName":"Protocols","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocol","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"Protocols allows for more fine-grain matching of traffic on\nprotocol-specific attributes such as the port. If\nunspecified, protocol-specific attributes will not be used\nto match traffic.\n\n+optional\n+kubebuilder:validation:MinItems=1\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Protocols allows for more fine-grain matching of traffic on protocol-specific attributes such as the port. If unspecified, protocol-specific attributes will not be used to match traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MinItems=1"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyIngressRule describes an action to take on a particular\nset of traffic destined for pods selected by a ClusterNetworkPolicy's\nSubject field.","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyIngressRule describes an action to take on a particular set of traffic destined for pods selected by a ClusterNetworkPolicy's Subject field."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyList":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyList","fields":[{"fieldName":"TypeMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.TypeMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"ListMeta","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.ListMeta","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"","parsedDocString":{"elements":null}},{"fieldName":"Items","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicy","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"","parsedDocString":{"elements":null}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyList contains a list of ClusterNetworkPolicy\n\n+kubebuilder:object:root=true\n+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyList contains a list of ClusterNetworkPolicy"]},{"type":"d","content":["+kubebuilder:object:root=true"]},{"type":"d","content":["+k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocol":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyProtocol","fields":[{"fieldName":"TCP","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocolTCP","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"TCP specific protocol matches.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["TCP specific protocol matches."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"UDP","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocolUDP","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"UDP specific protocol matches.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["UDP specific protocol matches."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"SCTP","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocolSCTP","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"SCTP specific protocol matches.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["SCTP specific protocol matches."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"DestinationNamedPort","typeName":"string","package":"","typeDecorators":null,"docString":"DestinationNamedPort selects a destination port on a pod based on the\nContainerPort name. You can't use this in a rule that targets resources\nwithout named ports (e.g. Nodes or Networks).\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["DestinationNamedPort selects a destination port on a pod based on the ContainerPort name. You can't use this in a rule that targets resources without named ports (e.g. Nodes or Networks)."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyProtocol describes additional protocol-specific match rules.\nExactly one field must be set.\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyProtocol describes additional protocol-specific match rules. Exactly one field must be set."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocolSCTP":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyProtocolSCTP","fields":[{"fieldName":"DestinationPort","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.Port","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"DestinationPort for the match.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["DestinationPort for the match."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyProtocolSCTP are SCTP attributes to be matched.\n\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyProtocolSCTP are SCTP attributes to be matched."]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocolTCP":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyProtocolTCP","fields":[{"fieldName":"DestinationPort","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.Port","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"DestinationPort for the match.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["DestinationPort for the match."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyProtocolTCP are TCP attributes to be matched.\n\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyProtocolTCP are TCP attributes to be matched."]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyProtocolUDP":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyProtocolUDP","fields":[{"fieldName":"DestinationPort","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.Port","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"DestinationPort for the match.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["DestinationPort for the match."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyProtocolUDP are UDP attributes to be matched.\n\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyProtocolUDP are UDP attributes to be matched."]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyRuleAction":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyRuleAction","fields":[],"enumValues":[{"name":"ClusterNetworkPolicyRuleActionAccept","docString":"ClusterNetworkPolicyRuleActionAccept indicates that\nmatching traffic will be accepted and no further policy\nevaluation will be done. This is a final decision.","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyRuleActionAccept indicates that matching traffic will be accepted and no further policy evaluation will be done. This is a final decision."]}]}},{"name":"ClusterNetworkPolicyRuleActionDeny","docString":"ClusterNetworkPolicyRuleActionDeny indicates that matching traffic\nwill be denied and no further policy evaluation will be done.\nThis is a final decision.","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyRuleActionDeny indicates that matching traffic will be denied and no further policy evaluation will be done. This is a final decision."]}]}},{"name":"ClusterNetworkPolicyRuleActionPass","docString":"ClusterNetworkPolicyRuleActionPass indicates that matching traffic\nwill jump to the next tier evaluation. That means that all the rules\nwith lower precedence at the same tier will be ignored,\nbut evaluation will continue at the next tier.\nFor example, if an Admin tier CNP uses Pass action,\nNetworkPolicy evaluation will happen next.","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyRuleActionPass indicates that matching traffic will jump to the next tier evaluation. That means that all the rules with lower precedence at the same tier will be ignored, but evaluation will continue at the next tier. For example, if an Admin tier CNP uses Pass action, NetworkPolicy evaluation will happen next."]}]}}],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyRuleAction string describes the ClusterNetworkPolicy\naction type.\n\n+enum\n+kubebuilder:validation:Enum={\"Accept\", \"Deny\", \"Pass\"}","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyRuleAction string describes the ClusterNetworkPolicy action type."]},{"type":"d","content":["+enum"]},{"type":"d","content":["+kubebuilder:validation:Enum={\"Accept\", \"Deny\", \"Pass\"}"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicySpec":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicySpec","fields":[{"fieldName":"Tier","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.Tier","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":null,"docString":"Tier is used as the top-level grouping for network policy prioritization.\n\nPolicy tiers are evaluated in the following order:\n* Admin tier\n* NetworkPolicy tier\n* Baseline tier\n\nClusterNetworkPolicy can use 2 of these tiers: Admin and Baseline.\n\nThe Admin tier takes precedence over all other policies. Policies\ndefined in this tier are used to set cluster-wide security rules\nthat cannot be overridden in the other tiers. If Admin tier has\nmade a final decision (Accept or Deny) on a connection, then no\nfurther evaluation is done.\n\nNetworkPolicy tier is the tier for the namespaced v1.NetworkPolicy.\nThese policies are intended for the application developer to describe\nthe security policy associated with their deployments inside their\nnamespace. v1.NetworkPolicy always makes a final decision for selected\npods. Further evaluation only happens for Pods not selected by a\nv1.NetworkPolicy.\n\nBaseline tier is a cluster-wide policy that can be overridden by the\nv1.NetworkPolicy. If Baseline tier has made a final decision (Accept or\nDeny) on a connection, then no further evaluation is done.\n\nIf a given connection wasn't allowed or denied by any of the tiers,\nthe default kubernetes policy is applied, which says that\nall pods can communicate with each other.","parsedDocString":{"elements":[{"type":"p","content":["Tier is used as the top-level grouping for network policy prioritization."]},{"type":"p","content":["Policy tiers are evaluated in the following order: * Admin tier * NetworkPolicy tier * Baseline tier"]},{"type":"p","content":["ClusterNetworkPolicy can use 2 of these tiers: Admin and Baseline."]},{"type":"p","content":["The Admin tier takes precedence over all other policies. Policies defined in this tier are used to set cluster-wide security rules that cannot be overridden in the other tiers. If Admin tier has made a final decision (Accept or Deny) on a connection, then no further evaluation is done."]},{"type":"p","content":["NetworkPolicy tier is the tier for the namespaced v1.NetworkPolicy. These policies are intended for the application developer to describe the security policy associated with their deployments inside their namespace. v1.NetworkPolicy always makes a final decision for selected pods. Further evaluation only happens for Pods not selected by a v1.NetworkPolicy."]},{"type":"p","content":["Baseline tier is a cluster-wide policy that can be overridden by the v1.NetworkPolicy. If Baseline tier has made a final decision (Accept or Deny) on a connection, then no further evaluation is done."]},{"type":"p","content":["If a given connection wasn't allowed or denied by any of the tiers, the default kubernetes policy is applied, which says that all pods can communicate with each other."]}]}},{"fieldName":"Priority","typeName":"int32","package":"","typeDecorators":null,"docString":"Priority is a value from 0 to 1000 indicating the precedence of\nthe policy within its tier. Policies with lower priority values have\nhigher precedence, and are checked before policies with higher priority\nvalues in the same tier. All Admin tier rules have higher precedence than\nNetworkPolicy or Baseline tier rules.\nIf two (or more) policies in the same tier with the same priority\ncould match a connection, then the implementation can apply any of the\nmatching policies to the connection, and there is no way for the user to\nreliably determine which one it will choose. Administrators must be\ncareful about assigning the priorities for policies with rules that will\nmatch many connections, and ensure that policies have unique priority\nvalues in cases where ambiguity would be unacceptable.\n\n+kubebuilder:validation:Minimum=0\n+kubebuilder:validation:Maximum=1000","parsedDocString":{"elements":[{"type":"p","content":["Priority is a value from 0 to 1000 indicating the precedence of the policy within its tier. Policies with lower priority values have higher precedence, and are checked before policies with higher priority values in the same tier. All Admin tier rules have higher precedence than NetworkPolicy or Baseline tier rules. If two (or more) policies in the same tier with the same priority could match a connection, then the implementation can apply any of the matching policies to the connection, and there is no way for the user to reliably determine which one it will choose. Administrators must be careful about assigning the priorities for policies with rules that will match many connections, and ensure that policies have unique priority values in cases where ambiguity would be unacceptable."]},{"type":"d","content":["+kubebuilder:validation:Minimum=0"]},{"type":"d","content":["+kubebuilder:validation:Maximum=1000"]}]}},{"fieldName":"Subject","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicySubject","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":null,"docString":"Subject defines the pods to which this ClusterNetworkPolicy applies.","parsedDocString":{"elements":[{"type":"p","content":["Subject defines the pods to which this ClusterNetworkPolicy applies."]}]}},{"fieldName":"Ingress","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyIngressRule","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"Ingress is the list of Ingress rules to be applied to the selected pods.\n\nA maximum of 25 rules is allowed in this block.\n\nThe relative precedence of ingress rules within a single CNP object\n(all of which share the priority) will be determined by the order\nin which the rule is written.\nThus, a rule that appears at the top of the ingress rules\nwould take the highest precedence.\nCNPs with no ingress rules do not affect ingress traffic.\n\n+optional\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Ingress is the list of Ingress rules to be applied to the selected pods."]},{"type":"p","content":["A maximum of 25 rules is allowed in this block."]},{"type":"p","content":["The relative precedence of ingress rules within a single CNP object (all of which share the priority) will be determined by the order in which the rule is written. Thus, a rule that appears at the top of the ingress rules would take the highest precedence. CNPs with no ingress rules do not affect ingress traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}},{"fieldName":"Egress","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyEgressRule","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["List"],"docString":"Egress is the list of Egress rules to be applied to the selected pods.\n\nA maximum of 25 rules is allowed in this block.\n\nThe relative precedence of egress rules within a single CNP object\n(all of which share the priority) will be determined by the order\nin which the rule is written.\nThus, a rule that appears at the top of the egress rules\nwould take the highest precedence.\nCNPs with no egress rules do not affect egress traffic.\n\n+optional\n+kubebuilder:validation:MaxItems=25","parsedDocString":{"elements":[{"type":"p","content":["Egress is the list of Egress rules to be applied to the selected pods."]},{"type":"p","content":["A maximum of 25 rules is allowed in this block."]},{"type":"p","content":["The relative precedence of egress rules within a single CNP object (all of which share the priority) will be determined by the order in which the rule is written. Thus, a rule that appears at the top of the egress rules would take the highest precedence. CNPs with no egress rules do not affect egress traffic."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:MaxItems=25"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicySpec defines the desired state of ClusterNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicySpec defines the desired state of ClusterNetworkPolicy."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicyStatus":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicyStatus","fields":[{"fieldName":"Conditions","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.Condition","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["List"],"docString":"+patchMergeKey=type\n+patchStrategy=merge\n+listType=map\n+listMapKey=type","parsedDocString":{"elements":[{"type":"d","content":["+patchMergeKey=type"]},{"type":"d","content":["+patchStrategy=merge"]},{"type":"d","content":["+listType=map"]},{"type":"d","content":["+listMapKey=type"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicyStatus defines the observed state of\nClusterNetworkPolicy.","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicyStatus defines the observed state of ClusterNetworkPolicy."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.ClusterNetworkPolicySubject":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"ClusterNetworkPolicySubject","fields":[{"fieldName":"Namespaces","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":["Ptr"],"docString":"Namespaces is used to select pods via namespace selectors.\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Namespaces is used to select pods via namespace selectors."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"Pods","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.NamespacedPod","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"Pods is used to select pods via namespace AND pod selectors.\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Pods is used to select pods via namespace AND pod selectors."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"ClusterNetworkPolicySubject defines what resources the policy applies to.\nExactly one field must be set.\nNote that host-networked pods are not included in subject selection.\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["ClusterNetworkPolicySubject defines what resources the policy applies to. Exactly one field must be set. Note that host-networked pods are not included in subject selection."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.NamespacedPod":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"NamespacedPod","fields":[{"fieldName":"NamespaceSelector","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"NamespaceSelector follows standard label selector\nsemantics; if empty, it selects all Namespaces.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["NamespaceSelector follows standard label selector semantics; if empty, it selects all Namespaces."]},{"type":"d","content":["+optional"]}]}},{"fieldName":"PodSelector","typeName":"k8s.io/apimachinery/pkg/apis/meta/v1.LabelSelector","package":"k8s.io/apimachinery/pkg/apis/meta/v1","typeDecorators":null,"docString":"PodSelector is used to explicitly select pods within a namespace;\nif empty, it selects all Pods.\n\n+required","parsedDocString":{"elements":[{"type":"p","content":["PodSelector is used to explicitly select pods within a namespace; if empty, it selects all Pods."]},{"type":"d","content":["+required"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"NamespacedPod allows the user to select a given set of pod(s) in\nselected namespace(s).","parsedDocString":{"elements":[{"type":"p","content":["NamespacedPod allows the user to select a given set of pod(s) in selected namespace(s)."]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.Port":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"Port","fields":[{"fieldName":"Number","typeName":"int32","package":"","typeDecorators":null,"docString":"Number defines a network port value.\n\n+optional\n+kubebuilder:validation:Minimum=1\n+kubebuilder:validation:Maximum=65535","parsedDocString":{"elements":[{"type":"p","content":["Number defines a network port value."]},{"type":"d","content":["+optional"]},{"type":"d","content":["+kubebuilder:validation:Minimum=1"]},{"type":"d","content":["+kubebuilder:validation:Maximum=65535"]}]}},{"fieldName":"Range","typeName":"sigs.k8s.io/network-policy-api/apis/v1alpha2.PortRange","package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeDecorators":["Ptr"],"docString":"Range defines a contiguous range of ports.\n\n+optional","parsedDocString":{"elements":[{"type":"p","content":["Range defines a contiguous range of ports."]},{"type":"d","content":["+optional"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"Port matches on port number. You must specify either Port or Range.\n\n+kubebuilder:validation:MaxProperties=1\n+kubebuilder:validation:MinProperties=1","parsedDocString":{"elements":[{"type":"p","content":["Port matches on port number. You must specify either Port or Range."]},{"type":"d","content":["+kubebuilder:validation:MaxProperties=1"]},{"type":"d","content":["+kubebuilder:validation:MinProperties=1"]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.PortRange":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"PortRange","fields":[{"fieldName":"Start","typeName":"int32","package":"","typeDecorators":null,"docString":"start defines a network port that is the start of a port\nrange, the Start value must be less than End.\n\n+required\n+kubebuilder:validation:Minimum=1\n+kubebuilder:validation:Maximum=65535","parsedDocString":{"elements":[{"type":"p","content":["start defines a network port that is the start of a port range, the Start value must be less than End."]},{"type":"d","content":["+required"]},{"type":"d","content":["+kubebuilder:validation:Minimum=1"]},{"type":"d","content":["+kubebuilder:validation:Maximum=65535"]}]}},{"fieldName":"End","typeName":"int32","package":"","typeDecorators":null,"docString":"end specifies the last port in the range. It must be\ngreater than start.\n\n+required\n+kubebuilder:validation:Minimum=1\n+kubebuilder:validation:Maximum=65535","parsedDocString":{"elements":[{"type":"p","content":["end specifies the last port in the range. It must be greater than start."]},{"type":"d","content":["+required"]},{"type":"d","content":["+kubebuilder:validation:Minimum=1"]},{"type":"d","content":["+kubebuilder:validation:Maximum=65535"]}]}}],"enumValues":[],"isRoot":false,"isTopLevel":true,"docString":"PortRange defines an inclusive range of ports from the assigned\nStart value to End value.\n\n+kubebuilder:validation:XValidation:rule=\"self.start \u003c self.end\", message=\"Start port must be less than End port\"","parsedDocString":{"elements":[{"type":"p","content":["PortRange defines an inclusive range of ports from the assigned Start value to End value."]},{"type":"d","content":["+kubebuilder:validation:XValidation:rule=\"self.start \u003c self.end\", message=\"Start port must be less than End port\""]}]}},"sigs.k8s.io/network-policy-api/apis/v1alpha2.Tier":{"package":"sigs.k8s.io/network-policy-api/apis/v1alpha2","typeName":"Tier","fields":[],"enumValues":[{"name":"AdminTier","docString":"","parsedDocString":{"elements":null}},{"name":"BaselineTier","docString":"","parsedDocString":{"elements":null}}],"isRoot":false,"isTopLevel":true,"docString":"+kubebuilder:validation:Enum={\"Admin\", \"Baseline\"}","parsedDocString":{"elements":[{"type":"d","content":["+kubebuilder:validation:Enum={\"Admin\", \"Baseline\"}"]}]}}};
